ontology.content:
@prefix adms: <http://www.w3.org/ns/adms#> .
@prefix dcterms: <http://purl.org/dc/terms/> .
@prefix epo: <http://data.europa.eu/a4g/ontology#> .
@prefix m8g: <http://data.europa.eu/m8g/> .
@prefix org: <http://www.w3.org/ns/org#> .
@prefix owl: <http://www.w3.org/2002/07/owl#> .
@prefix rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#> .
@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .
@prefix skos: <http://www.w3.org/2004/02/skos/core#> .
@prefix time: <http://www.w3.org/2006/time#> .
@prefix vann: <http://purl.org/vocab/vann/> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

epo:Business a owl:Class ;
    skos:definition "A private law company registered in a national registry."@en ;
    skos:historyNote "WG Approval 28/04/2020"@en ;
    skos:prefLabel "Business"@en .

epo:Buyer a owl:Class ;
    rdfs:subClassOf epo:AcquiringParty ;
    skos:definition "A Role of an Agent that awards a Contract and/or purchases items. Additional information: In Public Procurement the Role of Buyer is carried out by the following types of Organisation: Contracting Authority, Contracting Entity, a defense Contractor, an international Organisation, or an organisation awarding a Contract subsidized by a Contracting Authority. In Pre-Award, the Buyer generally awards the Contract, however future purchasers may be foreseen. In Post-Award the buyer generally refers to the purchaser of items."@en ;
    skos:prefLabel "Buyer"@en .

epo:Contract a owl:Class ;
    skos:definition "A voluntary, deliberate, and legally binding agreement between two or more competent parties."@en ;
    skos:historyNote "WG approval 19/03/2024"@en ;
    skos:prefLabel "Contract"@en .

epo:ESPD a owl:Class ;
    rdfs:subClassOf epo:Document ;
    skos:definition "A self-declaration of an economic operator, stating that it does not fall under the Exclusion Grounds and that it meets the Selection Criteria for a specific procurement."@en ;
    skos:historyNote "WG Approval 05/03/2024"@en ;
    skos:prefLabel "ESPD"@en .

epo:Item a owl:Class ;
    rdfs:subClassOf epo:AbstractItem ;
    skos:definition "A product, work, service or any combination of them. Additional Information: An Item can be an atomic Thing or a composition of things that together are seen as a unit, e.g. a tetrabrik of milk or an indivisible package of six tetrabriks. No distinction is provided between services, goods and works to leave room for innovation. An Item is used to fulfill a need which is described in an Item Request."@en ;
    skos:historyNote "WG approval 09/10/2025"@en ;
    skos:prefLabel "Item"@en .

epo:announcesProcedure a owl:ObjectProperty ;
    rdfs:domain [ a owl:Class ;
            owl:unionOf ( epo:PlanningNotice epo:DirectAwardPrenotificationNotice epo:CompetitionNotice ) ],
        [ a owl:Class ;
            owl:unionOf ( epo:CompetitionNotice epo:DirectAwardPrenotificationNotice epo:PlanningNotice ) ] ;
    rdfs:range epo:Procedure ;
    rdfs:subPropertyOf epo:concernsProcedure ;
    skos:definition "Relation indicating the formal communication of a Procedure."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "announces Procedure"@en .

epo:answersReviewRequest a owl:ObjectProperty ;
    rdfs:domain epo:ReviewDecision ;
    rdfs:range epo:ReviewRequest ;
    skos:definition "Responds to a Review Request."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "answers Review Request"@en .

epo:comprisesOrderResponseLine a owl:ObjectProperty ;
    rdfs:domain epo:OrderResponse ;
    rdfs:range epo:OrderResponseLine ;
    skos:definition "Incorporates Order Response Line."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "comprises Order Response Line"@en .

epo:concernsEnergyEfficiencyItemCategory a owl:ObjectProperty ;
    rdfs:domain epo:EnergyEfficiencyInformation ;
    rdfs:range skos:Concept ;
    skos:definition "Relates to Energy Efficiency Item Category."@en ;
    skos:prefLabel "concerns Energy Efficiency Item Category"@en .

epo:concernsNotice a owl:ObjectProperty ;
    rdfs:domain [ a owl:Class ;
            owl:unionOf ( epo:NonPublishedInformation epo:ChangeInformation ) ] ;
    rdfs:range epo:Notice ;
    skos:definition "Relates to Notice."@en ;
    skos:historyNote "WG Approval 14/05/2024"@en ;
    skos:prefLabel "concerns Notice"@en .

epo:containsCandidate a owl:ObjectProperty ;
    rdfs:domain [ a owl:Class ;
            owl:unionOf ( epo:SelectedCandidateList epo:ExcludedCandidateList ) ],
        epo:ExcludedCandidateList ;
    rdfs:range epo:Candidate ;
    skos:definition "Includes Candidate."@en ;
    skos:historyNote "WG Approval 14/05/2024"@en ;
    skos:prefLabel "contains Candidate"@en .

epo:describesItem a owl:ObjectProperty ;
    rdfs:domain epo:ItemProperty ;
    rdfs:range epo:AbstractItem ;
    skos:definition "Characterises Item."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "describes Item"@en .

epo:evaluatesProcurementCriterion a owl:ObjectProperty ;
    rdfs:domain epo:EvaluationCriterion ;
    rdfs:range epo:ProcurementCriterion ;
    skos:definition "Assesses Procurement Criterion."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "evaluates Procurement Criterion"@en .

epo:foreseesSubcontracting a owl:ObjectProperty ;
    rdfs:domain epo:Tender ;
    rdfs:range epo:SubcontractingEstimate ;
    skos:definition "Relation indicating that an instance of the concept plans to be Subcontracted."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "foresees Subcontracting"@en .

epo:hasAcceptanceStatus a owl:ObjectProperty ;
    rdfs:domain [ a owl:Class ;
            owl:unionOf ( epo:AbstractContainer epo:ReceiptAdviceInformation ) ],
        [ a owl:Class ;
            owl:unionOf ( epo:ReceiptAdviceInformation epo:AbstractContainer ) ] ;
    rdfs:range skos:Concept ;
    skos:definition "Relation indicating the acceptance status."@en ;
    skos:prefLabel "has Acceptance Status"@en .

epo:hasActualDeliveryDate a owl:DatatypeProperty ;
    rdfs:domain epo:DeliveryInformation ;
    rdfs:range xsd:dateTime ;
    skos:definition "The date when the Delivery occured. (epo-ord:DeliveryInformation)"@en ;
    skos:historyNote "WG approval 25/09/2026"@en ;
    skos:prefLabel "has Actual Delivery Date"@en .

epo:hasBuyerItemID a owl:ObjectProperty ;
    rdfs:domain epo:AbstractItem ;
    rdfs:range adms:Identifier ;
    skos:definition "The general identifier assigned to the concept as defined by the Buyer.​"@en ;
    skos:historyNote "WG Approval 16/05/2023"@en ;
    skos:prefLabel "has Buyer Item ID"@en .

epo:hasCalculationBasedOn a owl:ObjectProperty ;
    rdfs:domain epo:EnergyEfficiencyInformation ;
    rdfs:range skos:Concept ;
    skos:definition "Relation indicating the basis for the calculation of the energy efficiency."@en ;
    skos:prefLabel "has Calculation Based On"@en .

epo:hasDespatchedQuantity a owl:ObjectProperty ;
    rdfs:domain epo:DespatchLine ;
    rdfs:range epo:Quantity ;
    skos:definition "The Quantity that has been sent."@en ;
    skos:historyNote "WG Approval 18/06/2024"@en ;
    skos:prefLabel "has Despatched Quantity"@en .

epo:hasDocumentType a owl:ObjectProperty ;
    rdfs:domain epo:Document ;
    rdfs:range skos:Concept ;
    skos:definition "Relation indicating the Document Type."@en ;
    skos:prefLabel "has Document Type"@en .

epo:hasElementReference a owl:DatatypeProperty ;
    rdfs:domain epo:ReviewInformation ;
    rdfs:range xsd:anyURI ;
    skos:definition "Reference to the class instance in the current notice. (epo:ReviewInformation)"@en ;
    skos:editorialNote "Used by eForms BT-13716, eForms BT-786, eForms BT-1501"@en ;
    skos:prefLabel "has Element Reference"@en .

epo:hasEnvironmentalEmissionCode a owl:ObjectProperty ;
    rdfs:domain epo:EnvironmentalEmissionInformation ;
    rdfs:range skos:Concept ;
    skos:definition "Relation indicating the Environmental Emission Code."@en ;
    skos:prefLabel "has Environmental Emission Code"@en .

epo:hasFormula a owl:DatatypeProperty ;
    rdfs:domain epo:ProcurementCriterion ;
    rdfs:range rdf:PlainLiteral ;
    skos:definition "The mathematical equation or any other description used for complicated weighing of criteria (e.g. non-linear weighing, the analytic hierarchy process) when a weighing cannot be expressed per criterion. (epo:ProcurementCriterion)"@en ;
    skos:editorialNote "Used by eForms BT-543"@en ;
    skos:prefLabel "has Formula"@en .

epo:hasItemClassification a owl:ObjectProperty ;
    rdfs:domain epo:AbstractItem ;
    rdfs:range skos:Concept ;
    skos:definition "A classification of this item according to a specific system for classifying products or services. Additional information: Examples of classification schemes are: CPV, UNSPC, eCl@ss, GPC, ..."@en ;
    skos:prefLabel "has Item Classification"@en .

epo:hasMaximumMeasure a owl:ObjectProperty ;
    rdfs:domain epo:DimensionInformation ;
    rdfs:range epo:Quantity ;
    skos:definition "Relation indicating the upper limit of the measure."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Maximum Measure"@en .

epo:hasMaximumNumberOfCandidates a owl:DatatypeProperty ;
    rdfs:domain epo:MultipleStageProcedureTerm ;
    rdfs:range xsd:integer ;
    skos:definition "Maximum number of candidates to be invited for the second stage of the procedure. (epo:MultipleStageProcedureTerm)"@en ;
    skos:historyNote "WG Approval 22/08/2019"@en ;
    skos:prefLabel "has Maximum Number Of Candidates"@en .

epo:hasMeasuredAttributeCode a owl:ObjectProperty ;
    rdfs:domain epo:DimensionInformation ;
    rdfs:range skos:Concept ;
    skos:definition "Relation indicating the Measured Attribute Code."@en ;
    skos:prefLabel "has Measured Attribute Code"@en .

epo:hasMinimumMeasure a owl:ObjectProperty ;
    rdfs:domain epo:DimensionInformation ;
    rdfs:range epo:Quantity ;
    skos:definition "Relation indicating the lower limit of the measure."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Minimum Measure"@en .

epo:hasMinimumNumberOfCandidates a owl:DatatypeProperty ;
    rdfs:domain epo:MultipleStageProcedureTerm ;
    rdfs:range xsd:integer ;
    skos:definition "Minimum number of candidates to be invited for the second stage of the procedure. (epo:MultipleStageProcedureTerm)"@en ;
    skos:historyNote "WG Approval 22/08/2019"@en ;
    skos:prefLabel "has Minimum Number Of Candidates"@en .

epo:hasNetQuantity a owl:ObjectProperty ;
    rdfs:domain epo:AbstractItem ;
    rdfs:range epo:Quantity ;
    skos:definition "The net quantity of the item that is contained in each consumable unit, excluding any packaging materials."@en ;
    skos:prefLabel "has Net Quantity"@en .

epo:hasNoticeType a owl:ObjectProperty ;
    rdfs:domain epo:Notice ;
    rdfs:range skos:Concept ;
    skos:definition "Relation indicating the Notice Type."@en ;
    skos:prefLabel "has Notice Type"@en .

epo:hasOutstandingQuantity a owl:ObjectProperty ;
    rdfs:domain epo:DespatchLine ;
    rdfs:range epo:Quantity ;
    skos:definition "The Quantity of non-despatched Goods Items."@en ;
    skos:historyNote "WG Approval 05/06/2024"@en ;
    skos:prefLabel "has Outstanding Quantity"@en .

epo:hasProcedureType a owl:ObjectProperty ;
    rdfs:domain epo:Procedure ;
    rdfs:range skos:Concept ;
    skos:definition "Identification of the Procedure used."@en ;
    skos:prefLabel "has Procedure Type"@en .

epo:hasPublicationDate a owl:DatatypeProperty ;
    rdfs:domain epo:Document ;
    rdfs:range xsd:date ;
    skos:definition "Date of formal public issuance of the document. (epo:Document)"@en ;
    skos:historyNote "WG approval 20/06/2023"@en ;
    skos:prefLabel "has Publication Date"@en .

epo:hasQuantity a owl:ObjectProperty ;
    rdfs:domain [ a owl:Class ;
            owl:unionOf ( epo:OrderLine epo:InvoiceLine epo:Deliverable ) ],
        epo:Deliverable,
        epo:InvoiceLine,
        epo:OrderLine ;
    rdfs:range epo:Quantity ;
    skos:definition "Relation indicating that the instance of the concept has a Quantity."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Quantity"@en .

epo:hasResponseStatus a owl:ObjectProperty ;
    rdfs:domain epo:CatalogueResponseInformation ;
    rdfs:range skos:Concept ;
    skos:definition "Relation indicating the response status."@en ;
    skos:prefLabel "has Response Status"@en .

epo:hasReviewDecisionType a owl:ObjectProperty ;
    rdfs:domain epo:ReviewDecision ;
    rdfs:range skos:Concept ;
    skos:definition "Relation indicating the Review Decision Type."@en ;
    skos:prefLabel "has Review Decision Type"@en .

epo:hasReviewRequestFee a owl:ObjectProperty ;
    rdfs:domain epo:ReviewRequest ;
    rdfs:range epo:MonetaryValue ;
    skos:definition "Relation indicating the charge or cost required for processing the Review Request."@en ;
    skos:editorialNote "Used by eForms BT-795"@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Review Request Fee"@en .

epo:hasStatus a owl:ObjectProperty ;
    rdfs:domain [ a owl:Class ;
            owl:unionOf ( epo:OrderResponseInformation epo:OrderChangeLine ) ] ;
    rdfs:range skos:Concept ;
    skos:definition "Relation indicating the status."@en ;
    skos:prefLabel "has Status"@en .

epo:includesNationalCriterion a owl:ObjectProperty ;
    rdfs:domain epo:QualificationCriterion ;
    rdfs:range epo:QualificationCriterion ;
    skos:definition "Relation indicating that a Criterion contains a Criterion that is specific to a given Member State."@en ;
    skos:historyNote "WG approval 07/11/2023"@en ;
    skos:prefLabel "includes National Criterion"@en .

epo:isSpecificToOrderResponseLine a owl:ObjectProperty ;
    rdfs:domain epo:OrderResponseInformation ;
    rdfs:range epo:OrderResponseLine ;
    skos:definition "Information that is particular to an Order Response Line."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "is Specific To Order Response Line"@en .

epo:refersToNotice a owl:ObjectProperty ;
    rdfs:domain epo:ESPDRequest,
        epo:Notice ;
    rdfs:range epo:Notice ;
    skos:definition "Reference to a Notice."@en ;
    skos:historyNote "WG approval 12/03/2024"@en,
        "WG approval 25/09/2025"@en ;
    skos:prefLabel "refers To Notice"@en .

<https://github.com/citiususc/shard/tree/main/frontend/examples/epo-5.2.0-shard-demo-subset> a owl:Ontology ;
    dcterms:description "A reduced, domain-coherent subset of ePO 5.2.0 prepared for the preloaded SHARD Rule-to-Shape and Batch-to-Shapes demonstrations."@en ;
    dcterms:license <https://joinup.ec.europa.eu/collection/eupl/eupl-text-eupl-12> ;
    dcterms:publisher <http://publications.europa.eu/resource/authority/corporate-body/PUBL> ;
    dcterms:source epo: ;
    dcterms:title "ePO 5.2.0 SHARD demonstration subset"@en ;
    vann:preferredNamespacePrefix "epo" ;
    vann:preferredNamespaceUri epo: ;
    rdfs:seeAlso <https://github.com/OP-TED/ePO/releases> ;
    owl:versionInfo "5.2.0" .

epo:AcquiringParty a owl:Class ;
    rdfs:subClassOf epo:AgentInRole ;
    skos:definition "The Role of an Agent that acts on the buying side of a Procurement Process."@en ;
    skos:prefLabel "Acquiring Party"@en .

epo:AwardOutcome a owl:Class ;
    rdfs:subClassOf epo:ContextualProjection ;
    skos:definition "Result concerning the competition that was attributed by the Awarder."@en ;
    skos:historyNote "WG approval 19/03/2024"@en ;
    skos:prefLabel "Award Outcome"@en .

epo:Candidate a owl:Class ;
    rdfs:subClassOf epo:OfferingParty ;
    skos:definition "The Role of an Agent that has sought an invitation or has been invited to take part in a restricted Procedure, in a competitive Procedure with negotiation, in a negotiated Procedure without prior publication, in a competitive dialogue or in an innovation partnership."@en ;
    skos:historyNote "WG approval 30/05/2023"@en ;
    skos:prefLabel "Candidate"@en .

epo:CatalogueResponseInformation a owl:Class ;
    skos:definition "Information about a Catalogue Response."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Catalogue Response Information"@en .

epo:ConcessionEstimate a owl:Class ;
    rdfs:subClassOf epo:Estimate,
        epo:MaskableObject ;
    skos:definition "Approximation concerning the foreseen Concession Contract."@en ;
    skos:historyNote "WG approval 19/03/2024"@en ;
    skos:prefLabel "Concession Estimate"@en .

epo:ContextualProjection a owl:Class ;
    skos:definition "Projection of an Entity and all of its properties that hold in a given Situation Context. Additional Information: The contextual projection does not have its own identity (-I), is dependent (+D) on the described Entity, and is anti-rigid (~R) We say that ContextualProjection *describes* an Entity. Adaptation of ContextSlices pattern encoding a 4D view. http://ontologydesignpatterns.org/wiki/Submissions:Context_Slices"@en ;
    skos:prefLabel "Contextual Projection"@en .

epo:ContractLotCompletionInformation a owl:Class ;
    rdfs:subClassOf epo:ContextDescription ;
    skos:definition "Information related to a given Lot at the end of the procurement."@en ;
    skos:prefLabel "Contract Lot Completion Information"@en .

epo:DeliveryInformation a owl:Class ;
    rdfs:subClassOf epo:InformationHub ;
    skos:definition "Information about the timing, the delivery destination, the delivery agreement and the involved parties."@en ;
    skos:historyNote "WG Approval 16/05/2023"@en ;
    skos:prefLabel "Delivery Information"@en .

epo:EvaluationCriterion a owl:Class ;
    skos:definition "A Criterion used by the Buyer to assess and compare Tenders in order to determine which Offer best meets the objectives of the Procurement Procedure."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Evaluation Criterion"@en .

epo:ExpressionOfInterest a owl:Class ;
    skos:definition "Document presenting an Economic Operator's Request to be considered for Procedures covering a specific domain."@en ;
    skos:historyNote "WG approval 13/04/2021"@en ;
    skos:prefLabel "Expression Of Interest"@en .

epo:ItemProperty a owl:Class ;
    skos:definition "Construct meant to represent the association between an attribute defined in an external classification scheme and the value ascribed to it."@en ;
    skos:historyNote "WG Approval 26/07/2022"@en ;
    skos:prefLabel "Item Property"@en .

epo:Lot a owl:Class ;
    rdfs:subClassOf epo:ProcurementObject ;
    skos:definition "A qualitative, quantitative or strategic subdivision of the goods, services or works to be procured, allowing the award of one or more Contracts."@en ;
    skos:historyNote "WG approval 12/09/2018"@en ;
    skos:prefLabel "Lot"@en .

epo:LotAwardOutcome a owl:Class ;
    rdfs:subClassOf epo:AwardOutcome,
        epo:MaskableObject ;
    skos:definition "Result concerning the Lot that was attributed by the Awarder."@en ;
    skos:historyNote "WG Approval 19/03/2024"@en ;
    skos:prefLabel "Lot Award Outcome"@en .

epo:LotGroup a owl:Class ;
    skos:definition "Combination of several Lots to conduct comparative assessment of the Tenders. Additional Information: The comparative assessment may refer to the Selection Criteria, Award and Value that apply to several Lots. Pending of discussion with eForms Member States may provide that, where more than one lot may be awarded to the same tenderer, contracting authorities may award contracts combining several or all lots where they have specified in the contract notice or in the invitation to confirm interest that they reserve the possibility of doing so and indicate the lots or groups of lots that may be combined."@en ;
    skos:prefLabel "Lot Group"@en .

epo:MonetaryValue a owl:Class ;
    rdfs:subClassOf epo:MaskableObject ;
    skos:definition "A number of monetary units specified using a given unit of currency. Additional information: In the pre-award phase of the procurement, all monetary values are considered to exclude VAT based on the Directive 2014/24/EU."@en ;
    skos:historyNote "WG approval 13/04/2021"@en ;
    skos:prefLabel "Monetary Value"@en .

epo:NonPublishedInformation a owl:Class ;
    rdfs:subClassOf epo:ContextDescription ;
    skos:definition "Information about fields not published in this Notice. Additional Information: The non-published information may become available at a later date and may differ from one element to another within a given Document. Examples of fields that may not be immediately published are Winner, Tender and Procedure Lot Result, etc., e.g. for security reasons."@en ;
    skos:prefLabel "Non Published Information"@en .

epo:Order a owl:Class ;
    rdfs:subClassOf epo:PostAwardDocument ;
    skos:definition "A formal request of the Buyer to the Seller specifying the goods, services or works to be delivered. Additional Information: A Buyer submits an Order for delivery of goods, services or works to a Seller."@en ;
    skos:historyNote "WG Approval 23/04/2023"@en ;
    skos:prefLabel "Order"@en .

epo:OrderChangeLine a owl:Class ;
    rdfs:subClassOf epo:OrderLine ;
    skos:definition "Details concerning a given unit of goods, services or works requested in the Order Change."@en ;
    skos:historyNote "WG approval 16/09/2025"@en ;
    skos:prefLabel "Order Change Line"@en .

epo:OrderResponse a owl:Class ;
    rdfs:subClassOf epo:Order ;
    skos:definition "A formal reply from the Seller to the Buyer stating the Seller's ability to fulfil the order. Additional Information: The Order Response is used to inform on the acceptance or rejection of an Order or to make a counter-offer."@en ;
    skos:historyNote "WG Approval 20/04/2023"@en ;
    skos:prefLabel "Order Response"@en .

epo:PostAwardDocument a owl:Class ;
    rdfs:subClassOf epo:Document ;
    skos:definition "Document created after the award of a Contract during a Procurement Procedure."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Post Award Document"@en .

epo:ProcurementDocument a owl:Class ;
    skos:definition "Document produced or referred to by the Buyer to describe or determine elements of the Procurement. Additional information: Procurement Documents are to be accessible since the date of publication of the Contract Notice or the prior information Notice when used as a call for competition. Examples of Procurement Documents are Technical Specifications, the Descriptive Document, proposed conditions of Contract, formats for the presentation of Documents by Candidates and Tenderers, information on generally applicable obligations. Other Documents related to the Procedure such as Notices are not considered to be Procurement Documents."@en ;
    skos:historyNote "WG Approval 23/05/2019"@en ;
    skos:prefLabel "Procurement Document"@en .

epo:SubcontractingEstimate a owl:Class ;
    rdfs:subClassOf epo:Estimate,
        epo:MaskableObject ;
    skos:definition "Approximation concerning the foreseen Subcontracting."@en ;
    skos:historyNote "WG approval 19/03/2024"@en ;
    skos:prefLabel "Subcontracting Estimate"@en .

epo:Tender a owl:Class ;
    rdfs:subClassOf epo:MaskableObject ;
    skos:definition "Information submitted by the Economic Operator to specify its Offer regarding a specific Lot, in response to the call for Tender."@en ;
    skos:historyNote "WG approval 03/05/2022"@en ;
    skos:prefLabel "Tender"@en .

epo:Term a owl:Class ;
    skos:definition "A governing condition or stipulation."@en ;
    skos:prefLabel "Term"@en .

epo:TransportMeans a owl:Class ;
    skos:definition "Description of a particular vehicle or vessel used for the conveyance of goods or persons."@en ;
    skos:historyNote "WG Approval 21/05/2024"@en ;
    skos:prefLabel "Transport Means"@en .

epo:Winner a owl:Class ;
    rdfs:subClassOf epo:OfferingParty ;
    skos:definition "A Role of an Agent to whom a Lot is awarded."@en ;
    skos:historyNote "WG Approval 26/10/2021"@en ;
    skos:prefLabel "Winner"@en .

epo:concernsItem a owl:ObjectProperty ;
    rdfs:domain [ a owl:Class ;
            owl:unionOf ( epo:DimensionInformation epo:EnvironmentalEmissionInformation ) ] ;
    rdfs:range epo:AbstractItem ;
    skos:definition "Relates to Item."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "concerns Item"@en .

epo:concernsLot a owl:ObjectProperty ;
    rdfs:domain [ a owl:Class ;
            owl:unionOf ( epo:CompletionNotice epo:ContractModificationNotice epo:ContractLotCompletionInformation epo:ResultNotice epo:ProcurementProcessInformation epo:LotAwardOutcome m8g:InformationRequirement epo:EvidenceRequest epo:EvidenceSubmission ) ],
        [ a owl:Class ;
            owl:unionOf ( epo:EvidenceSubmission epo:EvidenceRequest ) ],
        [ a owl:Class ;
            owl:unionOf ( epo:CompletionNotice epo:ContractModificationNotice epo:ResultNotice ) ] ;
    rdfs:range epo:Lot ;
