epo:ESPDRequest a owl:Class ;
    rdfs:subClassOf [ a owl:Restriction ;
            owl:cardinality 1 ;
            owl:onProperty epo:concernsProcedure ],
        [ a owl:Restriction ;
            owl:minCardinality 1 ;
            owl:onProperty epo:specifiesProcurementCriterion ],
        [ a owl:Restriction ;
            owl:minCardinality 1 ;
            owl:onProperty epo:specifiesProcurementCriterion ],
        [ a owl:Restriction ;
            owl:cardinality 1 ;
            owl:onProperty epo:concernsProcedure ],
        epo:ProcurementDocument ;
    skos:definition "A document issued by a Buyer defining how the Exclusion Grounds and the Selection Criteria should be addressed in an European Single Procurement Document for a specific procurement."@en ;
    skos:historyNote "WG Approval 05/03/2024"@en ;
    skos:prefLabel "ESPD Request"@en .

epo:ProcurementCriterion a owl:Class ;
    skos:definition "A criterion specific to Procurement."@en ;
    skos:historyNote "WG Approval 23/04/2020"@en ;
    skos:prefLabel "Procurement Criterion"@en .

epo:ProcurementProcessInformation a owl:Class ;
    rdfs:subClassOf [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:isCompetitionTerminated ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:isDPSTerminated ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:concernsLot ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:concernsProcedure ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:isToBeRelaunched ],
        epo:ContextDescription ;
    skos:definition "Information about the temporal unfolding or succession of Procurement Objects."@en ;
    skos:prefLabel "Procurement Process Information"@en .

epo:QualificationCriterion a owl:Class ;
    rdfs:subClassOf [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:hasQualificationCriteriaStatedInProcurementDocuments ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:hasQualificationCriteriaStatedInNotice ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:hasQualificationCriteriaStatedInESPDRequest ],
        epo:ProcurementCriterion ;
    skos:definition "Criterion used in the first stage of procurement."@en ;
    skos:historyNote "WG approval 30/05/2023"@en ;
    skos:prefLabel "Qualification Criterion"@en .

epo:ReceiptAdviceLine a owl:Class ;
    rdfs:subClassOf [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:hasOversupplyQuantity ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:hasShortQuantity ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:hasRejectedQuantity ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:hasReceivedQuantity ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:hasOversupplyQuantity ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:hasRejectedQuantity ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:hasReceivedQuantity ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:hasShortQuantity ],
        [ a owl:Restriction ;
            owl:cardinality 1 ;
            owl:onProperty epo:isSubmittedForDespatchLine ],
        epo:Line ;
    skos:definition "Details concerning the Fulfilment of a Despatch Line."@en ;
    skos:historyNote "WG approval 16/09/2025"@en ;
    skos:prefLabel "Receipt Advice Line"@en .

epo:MaskableObject a owl:Class ;
    skos:definition "Entity within the procurement data model whose visibility, accessibility, or disclosure may be conditionally restricted due to legal, confidentiality, or security requirements."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Maskable Object"@en .

epo:EnvironmentalEmissionInformation a owl:Class ;
    rdfs:subClassOf [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:concernsTransportMeans ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:concernsItem ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:hasCalculationMethod ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:concernsTransportMeans ],
        [ a owl:Restriction ;
            owl:cardinality 1 ;
            owl:onProperty epo:hasMeasure ],
        [ a owl:Restriction ;
            owl:cardinality 1 ;
            owl:onProperty epo:hasMeasure ] ;
    skos:definition "Information about the emissions related to a product, work or service that are released into the environment."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Environmental Emission Information"@en .

epo:Line a owl:Class ;
    rdfs:subClassOf [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:hasAssociatedDocument ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:hasAdditionalInformation ],
        [ a owl:Restriction ;
            owl:cardinality 1 ;
            owl:onProperty epo:specifiesItem ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:hasAssociatedDocument ] ;
    skos:definition "Component of a document providing specific information."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Line"@en .

epo:ContextDescription a owl:Class ;
    skos:definition "A description concerning a Procurement Object or a Notice in a specific Situation Context. Additional Information: The description has its own identity (+I) but is dependent (+D) on the concerned Entity. We say that ContextDescription *concerns* an Entity."@en ;
    skos:prefLabel "Context Description"@en .

epo:DimensionInformation a owl:Class ;
    skos:definition "Information about the physical or measurable attributes of the instance of the concept described."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Dimension Information"@en .

epo:AbstractItem a owl:Class ;
    skos:definition "Gathering class for the Items, Item Requests and Deliverables. Additional information: The subclasses have in common that they are related to a procurement need."@en ;
    skos:historyNote "WG approval 09/10/2025"@en ;
    skos:prefLabel "Abstract Item"@en .

epo:Document a owl:Class ;
    skos:definition "A set of interrelated Business Information representing the Business facts and associated metadata. The information may be conveyed in any language, medium or form, including textual, numerical, graphic, cartographic, audio-visual forms, etc."@en ;
    skos:historyNote "WG approval 23/05/2019"@en ;
    skos:prefLabel "Document"@en .

epo:Notice a owl:Class ;
    skos:definition "Document published by the Buyer about market opportunities and results."@en ;
    skos:historyNote "WG Approval 23/05/2019"@en ;
    skos:prefLabel "Notice"@en .

epo:Quantity a owl:Class ;
    skos:definition "A counted number of non-monetary units possibly including fractions."@en ;
    skos:prefLabel "Quantity"@en .

